import { useEffect, useState } from 'react';
import './App.css';

function App() {
  const [destinos, setDestinos] = useState([]);
  const [cachoeiras, setCachoeiras] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function carregarDados() {
      try {
        const [resDestinos, resCachoeiras] = await Promise.all([
          fetch('/api/destinos'),
          fetch('/api/cachoeiras')
        ]);

        const destinosData = await resDestinos.json();
        const cachoeirasData = await resCachoeiras.json();

        setDestinos(destinosData);
        setCachoeiras(cachoeirasData);
      } catch (error) {
        console.error('Erro ao carregar dados da API:', error);
      } finally {
        setLoading(false);
      }
    }

    carregarDados();
  }, []);

  const rolarPara = (id) => {
    const secao = document.getElementById(id);
    if (secao) {
      secao.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <div className="pagina">
      <header className="hero">
        <div className="overlay">
          <nav className="topbar">
            <h1>MT Turismo</h1>
            <div className="botoes-nav">
              <button onClick={() => rolarPara('destinos')}>Pontos Turísticos</button>
              <button onClick={() => rolarPara('cachoeiras')}>Top 10 Cachoeiras</button>
            </div>
          </nav>

          <section className="hero-conteudo">
            <h2>Descubra o melhor do Mato Grosso</h2>
            <p>
              Natureza exuberante, ecoturismo, cultura regional e experiências incríveis
              no coração do Brasil.
            </p>
            <div className="hero-acoes">
              <button className="btn-destaque" onClick={() => rolarPara('destinos')}>
                Explorar destinos
              </button>
              <button className="btn-secundario" onClick={() => rolarPara('cachoeiras')}>
                Ver cachoeiras
              </button>
            </div>
          </section>
        </div>
      </header>

      <main className="conteudo">
        <section id="destinos" className="secao">
          <div className="secao-titulo">
            <h3>Pontos Turísticos do Mato Grosso</h3>
            <p>Locais imperdíveis para incluir no seu roteiro.</p>
          </div>

          {loading ? (
            <p>Carregando destinos...</p>
          ) : (
            <div className="grid-cards">
              {destinos.map((destino) => (
                <article className="card" key={destino.id}>
                  <img src={destino.imagem_url} alt={destino.nome} />
                  <div className="card-body">
                    <h4>{destino.nome}</h4>
                    <span>{destino.localizacao}</span>
                    <p>{destino.descricao}</p>
                  </div>
                </article>
              ))}
            </div>
          )}
        </section>

        <section id="cachoeiras" className="secao">
          <div className="secao-titulo">
            <h3>Top 10 Melhores Cachoeiras</h3>
            <p>As quedas d'água mais incríveis para curtir no estado.</p>
          </div>

          {loading ? (
            <p>Carregando cachoeiras...</p>
          ) : (
            <div className="grid-cards">
              {cachoeiras.map((cachoeira, index) => (
                <article className="card" key={cachoeira.id}>
                  <img src={cachoeira.imagem_url} alt={cachoeira.nome} />
                  <div className="card-body">
                    <h4>
                      #{index + 1} {cachoeira.nome}
                    </h4>
                    <span>
                      {cachoeira.municipio} • {cachoeira.altura_metros}m • Nível {cachoeira.nivel}
                    </span>
                    <p>{cachoeira.descricao}</p>
                  </div>
                </article>
              ))}
            </div>
          )}
        </section>
      </main>

      <footer className="rodape">
        <p>MT Turismo © 2026 • Mato Grosso em destaque para o mundo</p>
      </footer>
    </div>
  );
}

export default App;
